use dashmap::DashMap;use std::sync::Arc;pub struct C{d:Arc<DashMap<String,String>>}impl C{pub fn new()->Self{Self{d:Arc::new(DashMap::new())}}pub fn add(&self,k:String,v:String){self.d.insert(k,v);}pub fn get(&self,k:&str)->Option<String>{self.d.get(k).map(|v|v.clone())}}#[cfg(test)]mod tests{use super::*;#[test]fn t(){let c=C::new();c.add("k".into(),"v".into());assert!(c.get("k").is_some());}#[test]fn e(){assert!(C::new().get("x").is_none());}}
